document.addEventListener('DOMContentLoaded', function() {
    const apiKeyInput = document.getElementById('api_key');
    const languageSelect = document.getElementById('language');
    const complexitySelect = document.getElementById('complexity');
    const versionSelect = document.getElementById('version');
    const promptInput = document.getElementById('prompt');
    const generateButton = document.querySelector('.btn.btn-primary.btn-block');
    const codeOutput = document.getElementById('code-output');

    generateButton.addEventListener('click', generateProgram);

    function generateProgram() {
        const apiKey = apiKeyInput.value;
        const language = languageSelect.value;
        const complexity = complexitySelect.value;
        const version = versionSelect.value;
        const prompt = promptInput.value;

        if (!apiKey || !prompt) {
            alert('Por favor, insira sua chave de API e prompt.');
            return;
        }

        // Simulação de chamada de API para gerar código
        setTimeout(() => {
            const generatedCode = `Aqui está o código gerado para:\nLinguagem: ${language}\nComplexidade: ${complexity}\nVersão do ChatGPT: ${version}\nPrompt: ${prompt}\n\n// Seu código gerado estará aqui!`;
            codeOutput.textContent = generatedCode;
        }, 1000);
    }
});


